package com.chrisb97.warehouse.service;
import com.chrisb97.warehouse.dao.ProductDao;import com.chrisb97.warehouse.exception.ValidationException;import com.chrisb97.warehouse.model.*;import java.util.*;
public class PickingService{private final ProductDao productDao;private final RouteOptimizationService route;public PickingService(ProductDao p,RouteOptimizationService r){productDao=p;route=r;}public PickingRoute generate(List<PickingRequest> requests,List<Location> locations,boolean returnToEntrance){if(requests.isEmpty())throw new ValidationException("Add at least one item.");for(PickingRequest r:requests){if(r.requestedQuantity()>r.product().getQuantity())throw new ValidationException("Not enough stock for "+r.product().getSku()+".");}Map<Long,Location> map=new HashMap<>();for(Location l:locations)map.put(l.getId(),l);try{return route.optimize(route.groupByLocation(requests,map),returnToEntrance);}catch(IllegalArgumentException|NullPointerException e){throw new ValidationException(e.getMessage());}}}
